671	      setTimeout(() => {
672	        bootSequence.style.opacity = '0';
673	        bootSequence.style.transition = 'opacity 0.5s';
674	        setTimeout(() => {
675	          bootSequence.classList.add('hidden');
676	          localStorage.setItem('keating_boot_shown', 'true');
677	        }, 500);
678	      }, 3500);
679	    }
680	
681	    function openChat() {
682	      document.getElementById('chat-modal').classList.remove('hidden');
683	      document.body.style.overflow = 'hidden';
684	    }
685	    function closeChat() {
686	      document.getElementById('chat-modal').classList.add('hidden');
687	      document.body.style.overflow = '';
688	    }
689	    
690	    // Model loading state management
691	    const modelLoadingOverlay = document.getElementById('model-loading-overlay');
692	    const modelLoadProgress = document.getElementById('model-load-progress');
693	    const modelLoadPercent = document.getElementById('model-load-percent');
694	    const chatFrame = document.getElementById('chat-frame');
695	    let modelLoadShown = localStorage.getItem('keating_model_load_shown') === 'true';
696	
697	    // Listen for model loading messages from iframe
698	    window.addEventListener('message', (event) => {
699	      if (event.data.type === 'model-loading-start') {
700	        // Show loading overlay only on first load
701	        if (!modelLoadShown) {
702	          modelLoadingOverlay.classList.remove('hidden');
703	        }
704	      } else if (event.data.type === 'model-loading-progress') {
705	        const progress = event.data.progress;
706	        modelLoadProgress.style.width = progress + '%';
707	        modelLoadPercent.textContent = progress + '%';
708	      } else if (event.data.type === 'model-loading-complete') {
709	        localStorage.setItem('keating_model_load_shown', 'true');
710	        modelLoadShown = true;
711	        modelLoadingOverlay.classList.add('hidden');
712	      } else if (event.data.type === 'model-loading-error') {
713	        localStorage.setItem('keating_model_load_shown', 'true');
714	        modelLoadShown = true;
715	        modelLoadingOverlay.classList.add('hidden');
716	      }
717	    });
