2	import { Agent, type AgentMessage } from "@mariozechner/pi-agent-core";
3	import { getModel, streamSimple, type Context, type AssistantMessage, createAssistantMessageEventStream, type SimpleStreamOptions, type Model, type Api } from "@mariozechner/pi-ai";
4	import {
5		type AgentState,
6		ApiKeyPromptDialog,
7		AppStorage,
8		ChatPanel,
9		CustomProvidersStore,
10		IndexedDBStorageBackend,
11		ProviderKeysStore,
12		SessionsStore,
13		SettingsDialog,
14		SettingsStore,
15		setAppStorage,
16		defaultConvertToLlm,
17		ProxyTab,
18	} from "@mariozechner/pi-web-ui";
19	import { html, render } from "lit";
20	import { Settings } from "lucide";
21	import "./app.css";
22	import { icon } from "@mariozechner/mini-lit";
23	import { Button } from "@mariozechner/mini-lit/dist/Button.js";
24	
25	// Import custom components
26	import "./components/model-selector";
27	import "./components/providers-models-tab";
28	import "./components/settings";
29	import { KeatingProvidersModelsTab } from "./components/providers-models-tab";
30	import { KeatingModelSelector } from "./components/model-selector";
31	import { getProviderApiKey, syncCustomProviderKeys } from "./lib/provider-models";
32	import { localModel } from "./stores/local-model";
33	import { createKeatingTools, KEATING_SYSTEM_PROMPT as TOOLS_PROMPT } from "./keating/browser-tools";
34	import { KeatingStorage } from "./keating/storage";
35	
36	// Storage setup
37	const settings = new SettingsStore();
38	const providerKeys = new ProviderKeysStore();
39	const sessions = new SessionsStore();
40	const customProviders = new CustomProvidersStore();
41	
42	const backend = new IndexedDBStorageBackend({
43		dbName: "keating",
44		version: 1,
45		stores: [
46			settings.getConfig(),
47			providerKeys.getConfig(),
48			sessions.getConfig(),
49			SessionsStore.getMetadataConfig(),
50			customProviders.getConfig(),
51		],
52	});
53	
54	settings.setBackend(backend);
55	providerKeys.setBackend(backend);
56	sessions.setBackend(backend);
57	customProviders.setBackend(backend);
58	
59	const storage = new AppStorage(settings, providerKeys, sessions, customProviders, backend);
60	setAppStorage(storage);
61	
62	// Keating storage for tools/artifacts
63	const keatingStorage = new KeatingStorage();
64	
65	let currentSessionId: string | undefined;
66	let currentTitle = "Keating";
67	let isEditingTitle = false;
68	let agent: Agent;
69	let chatPanel: ChatPanel;
70	let agentUnsubscribe: (() => void) | undefined;
71	let selectedModel: Model<Api> | undefined;
72	let webGpuAvailable: boolean = false;
73	
74	const BROWSER_MODEL: Model<Api> = {
75		id: "gemma-4-e4b",
76		name: "Gemma 4 E4B (Browser)",
77		api: "browser" as Api,
78		provider: "browser",
79		baseUrl: "",
80		reasoning: false,
81		input: ["text"],
82		cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
83		contextWindow: 0,
84		maxTokens: 0,
85	};
86	
87	const DEFAULT_MODEL = getModel("google", "gemini-3.1-pro-preview");
88	
89	const createInitialModel = (): Model<Api> => selectedModel ?? DEFAULT_MODEL;
90	
91	// ============================================================================
92	// BROWSER MODEL STREAM FUNCTION
93	// ============================================================================
94	const createBrowserStreamFn = () => {
95		return async (model: Model<Api>, context: Context, options?: SimpleStreamOptions) => {
96			const stream = createAssistantMessageEventStream();
97			const abortSignal = options?.signal;
98	
99			// Default assistant message fields for browser model
100			const defaultFields = {
101				api: "browser" as const,
102				provider: "browser" as const,
103				model: "gemma-4-e4b",
104				usage: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, totalTokens: 0, cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, total: 0 } },
105			};
106	
107			// Don't block - run generation asynchronously
108			(async () => {
109				try {
110					if (abortSignal?.aborted) {
111						stream.end({
112							...defaultFields,
113							role: "assistant",
114							content: [],
115							stopReason: "aborted",
116							errorMessage: "Request aborted",
117							timestamp: Date.now(),
118						} as AssistantMessage);
119						return;
120					}
121	
122					// Extract user messages and format for local model
123					const userMessages = context.messages
124						.filter((m): m is Extract<typeof m, { role: "user" }> => m.role === "user")
125						.map(m => {
126							const content = m.content;
127							if (typeof content === "string") return content;
128							return content.filter((c): c is Extract<typeof c, { type: "text" }> => c.type === "text").map(c => c.text).join("\n");
129						});
130	
131					// Build prompt with system and messages
132					const systemPrompt = context.systemPrompt || "";
133					const conversationHistory = userMessages.join("\n\n");
